import path from "node:path";
import { fileURLToPath } from "node:url";
import { defineConfig, devices } from "@playwright/test";
import dotenv from "dotenv";
import { z } from "zod";

const configDirectory = path.dirname(fileURLToPath(import.meta.url));
/** Resolved from the config file so discovery works when CWD is the repo root (e.g. VS Code, `playwright --config apps/org-next/...`). */
const testsRoot = path.join(configDirectory, "tests");
const testEnvPath = path.resolve(configDirectory, ".env.e2e");
dotenv.config({ path: testEnvPath, override: true });

/** Matches `z.stringbool()` in `src/env.ts` (Zod v4 defaults: true, 1, yes, on, y, enabled, etc.). */
const rmpEnabled = z.stringbool().safeParse(process.env.VITE_ENABLE_RMP);
if (!rmpEnabled.success || rmpEnabled.data !== true) {
  throw new Error(
    "Playwright e2e requires server-side request mocking: set VITE_ENABLE_RMP=true in apps/org-next/.env.e2e " +
      "(request-mocking-protocol must forward x-mock-request for TanStack server functions). " +
      "In CI, set the same variable if you do not load that file.",
  );
}
